parameters.text:
=You are a multilingual compliance risk detection AI. 
Analyze the following email text:
Subject: {{ $('Catch Incoming Emails').item.json.subject }}
Body: {{ $json.clean_body }}

STRICTLY return valid JSON only, translated into English for standard reporting:
{
  "risk_type": "Fraud/Data Leak/Phishing/None",
  "risk_level": "High/Medium/Low",
  "confidence": 0-100,
  "reason": "Brief explanation in Markdown format"
}

parameters.jsCode:
for (const item of $input.all()) {
  let rawText = item.json.output || "";
  let cleanString = "";

  // Step 1: Hunt down the JSON inside the text (Ignore Markdown)
  const match = rawText.match(/\{[\s\S]*\}/);

  if (match) {
    cleanString = match[0];
  } else {
    // Fallback if there are no brackets found
    cleanString = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  }

  // Step 2: Safely attempt to parse the clean string into an object
  try {
    item.json.parsed_data = JSON.parse(cleanString);
  } catch (error) {
    // Safe fallback if the AI hallucinates completely invalid JSON
    item.json.parsed_data = {
      "risk_type": "Parse Error",
      "risk_level": "Medium",
      "confidence": 0,
      "reason": "System Error: AI generated invalid JSON formatting. Manual review required."
    };
  }
}

return $input.all();
